Decorator, bir fonksiyonu modifiye eden/genisleten fonksiyondur.

```python
# Temel decorator
def log(func):
    def wrapper(*args, **kwargs):
        print(f'{func.__name__} cagrildi')
        result = func(*args, **kwargs)
        print(f'{func.__name__} tamamlandi')
        return result
    return wrapper

@log
def topla(a, b):
    return a + b

# Parametreli decorator
def repeat(n):
    def decorator(func):
        def wrapper(*args, **kwargs):
            for _ in range(n):
                func(*args, **kwargs)
        return wrapper
    return decorator

@repeat(3)
def selamla():
    print('Merhaba!')

# Class decorator
class CallCounter:
    def __init__(self, func):
        self.func = func
        self.count = 0

    def __call__(self, *args, **kwargs):
        self.count += 1
        return self.func(*args, **kwargs)
```

Metaclass, siniflarin olusturuldugu siniftir. Sinif = Metaclass'in instance'i.

```python
# Temel metaclass
class SingletonMeta(type):
    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

class Database(metaclass=SingletonMeta):
    def __init__(self, url):
        self.url = url

db1 = Database('postgres://localhost')
db2 = Database('mysql://localhost')
print(db1 is db2)  # True

